      font-size: clamp(2rem, 5.5vw, 3.2rem);
      font-weight: 900;
      line-height: 1.15;
      margin-bottom: 16px;
    }
    .hero h1 .gradient-text {
      background: var(--gradient-cta);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
    }
    .hero p {
      color: var(--text-secondary);
      font-size: 1.1rem;
      max-width: 560px;
      margin: 0 auto 12px;
    }
    .hero-ctas {
      display: flex;
      gap: 12px;
      justify-content: center;
      flex-wrap: wrap;
      margin-top: 28px;
    }
    .hero-note {
      color: var(--text-secondary);
      font-size: .8rem;
      margin-top: 14px;
    }
    .hero-visual {
      margin-top: 48px;
      display: flex;
      justify-content: center;
      gap: 16px;
      flex-wrap: wrap;
    }
    .hero-visual    .demo-card {
      width: 280px;
      height: 200px;
      border-radius: var(--radius-lg);
      background: var(--bg-card);
      border: 1px solid var(--border);
      overflow: hidden;
      cursor: pointer;
      transition: transform .3s;
      position: relative;
    }
    .hero-visual .demo-card:hover { transform:scale(1.04); }
    .demo-card .placeholder-img {
      width:100%; height:100%;
      background: linear-gradient(135deg, rgba(180,74,255,0.2), rgba(255,107,53,0.1));
      display:flex; align-items:center; justify-content:center;
      font-size:3rem;
    }
    .demo-label {
      position:absolute; bottom:12px; left:12px;
      background:rgba(0,0,0,0.7); padding:4px 10px; border-radius:6px;
      font-size:.75rem; font-weight:600;
    }

    /* ========== FEATURES ========== */
    .features { padding: 80px 0; }
    .features-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(300px, 1fr));
      gap: 20px;
    }
    .feature-card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      padding: 28px 24px;
      transition: border-color .3s, transform .3s;
    }
    .feature-card:hover {
      border-color: var(--accent-purple);
      transform: translateY(-4px);
    }
    .feature-icon {
      width: 48px; height: 48px;
      border-radius: 12px;
      background: rgba(180,74,255,0.12);
      display: flex; align-items: center; justify-content: center;
      font-size: 1.4rem;
      margin-bottom: 16px;
    }
    .feature-card h3 {
      font-size: 1.1rem;
      font-weight: 700;
      margin-bottom: 8px;
    }
    .feature-card p {
      color: var(--text-secondary);
      font-size: .92rem;
      line-height: 1.55;
    }

    /* ========== HOW IT WORKS ========== */
    .how-it-works { padding: 80px 0; }
    .steps-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
      gap: 24px;
    }
    .step-card {
      text-align: center;
      padding: 32px 20px;
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      position: relative;
    }
    .step-number {
      width: 42px; height: 42px;
      border-radius: 50%;
      background: var(--gradient-cta);
      display: flex; align-items: center; justify-content: center;
      font-weight: 800;
      font-size: 1.1rem;
      margin: 0 auto 16px;
    }
    .step-card h3 { font-size:1.05rem; font-weight:700; margin-bottom:8px; }
    .step-card p { color:var(--text-secondary); font-size:.9rem; }

    /* ========== MODES ========== */
    .modes { padding:80px 0; }
    .modes-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
      gap: 16px;
    }
    .mode-card {
      border-radius: var(--radius);
      overflow: hidden;
      background: var(--bg-card);
      border: 1px solid var(--border);
      cursor: pointer;
      transition: transform .3s, border-color .3s;
    }
    .mode-card:hover { transform:translateY(-4px); border-color:var(--accent-purple); }
    .mode-img {
      width:100%; height:320px;
      background: linear-gradient(135deg, rgba(180,74,255,0.15), rgba(255,107,53,0.08));
      display:flex; align-items:center; justify-content:center;
      font-size:2.5rem;
      object-fit: cover;
    }
    .mode-badge {
      display:inline-block;
      background:var(--gradient-cta);
      color:#fff;
      font-size:.65rem;
      font-weight:700;
      padding:3px 8px;
      border-radius:4px;
      margin-bottom:6px;
      text-transform:uppercase;
      letter-spacing:.5px;
    }
    .mode-card .mode-info { padding:14px; }
    .mode-card h4 { font-size:.95rem; font-weight:700; margin-bottom:4px; }
    .mode-card p { color:var(--text-secondary); font-size:.82rem; line-height:1.5; }

    /* ========== WHY US ========== */
    .why-us { padding:80px 0; }
    .why-content {
      max-width:800px;
      margin:0 auto;
    }
    .why-content h3 {
      font-size:1.2rem;
      font-weight:700;
      margin-bottom:8px;
      color:var(--accent-purple);
    }
    .why-content p {
      color:var(--text-secondary);
      font-size:.95rem;
      margin-bottom:24px;
      line-height:1.65;
    }

    /* ========== COMPARISON ========== */
    .comparison { padding:80px 0; }
    .comparison-table {
      width:100%;
      border-collapse: collapse;
      background: var(--bg-card);
      border-radius: var(--radius);
      overflow: hidden;
      border: 1px solid var(--border);
    }
    .comparison-table th, .comparison-table td {
      padding: 14px 16px;
      text-align: center;
      font-size: .88rem;
      border-bottom: 1px solid var(--border);
    }
    .comparison-table th {
      background: rgba(180,74,255,0.1);
      font-weight: 700;
      font-size: .85rem;
      text-transform: uppercase;
      letter-spacing: .5px;
    }
    .comparison-table td:first-child { text-align:left; font-weight:600; }
    .comparison-table tr:last-child td { border-bottom:none; }
    .check { color:#4ade80; }
    .cross { color:#f87171; }
    .table-wrap { overflow-x:auto; }

    /* ========== PRICING ========== */
    .pricing { padding:80px 0; }
    .pricing-grid {
      display:grid;
      grid-template-columns: repeat(auto-fit, minmax(280px,1fr));
      gap:20px;
      max-width:960px;
      margin:0 auto;
    }
    .price-card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: var(--radius-lg);
      padding: 32px 24px;
      text-align: center;
      position: relative;
      transition: transform .3s, border-color .3s;
    }
    .price-card:hover { transform:translateY(-4px); }
    .price-card.featured {
      border-color: var(--accent-purple);
      box-shadow: 0 0 40px rgba(180,74,255,0.15);
    }
    .price-badge {
      position:absolute; top:-12px; left:50%; transform:translateX(-50%);
      background:var(--gradient-cta); padding:4px 16px; border-radius:20px;
      font-size:.75rem; font-weight:700;
    }
    .price-card h3 { font-size:1.15rem; font-weight:700; margin-bottom:8px; }
    .price-amount { font-size:2.4rem; font-weight:900; margin-bottom:4px; }
    .price-amount span { font-size:.9rem; font-weight:400; color:var(--text-secondary); }
    .price-card .price-desc { color:var(--text-secondary); font-size:.85rem; margin-bottom:20px; }
    .price-features { text-align:left; margin-bottom:24px; }
    .price-features li {
      color:var(--text-secondary);
      font-size:.88rem;
      padding:6px 0;
      display:flex;
      align-items:center;
      gap:8px;
    }
    .price-features li::before { content:'✓'; color:var(--accent-purple); font-weight:700; }

    /* ========== CLUSTER ========== */
    .cluster-section { padding:80px 0; }
    .cluster-grid {
      display:grid;
      grid-template-columns: repeat(auto-fit, minmax(240px,1fr));
      gap:16px;
    }
    .cluster-card {
      background:var(--bg-card);
      border:1px solid var(--border);
      border-radius:var(--radius);
      padding:24px;
      transition: border-color .3s;
    }
    .cluster-card:hover { border-color:var(--accent-purple); }
    .cluster-card h4 { font-size:1rem; font-weight:700; margin-bottom:6px; }
    .cluster-card p { color:var(--text-secondary); font-size:.88rem; margin-bottom:12px; }
    .cluster-card a { font-weight:600; font-size:.9rem; }

    /* ========== FAQ ========== */
    .faq { padding:80px 0; }
    .faq-list { max-width:800px; margin:0 auto; }
    .faq-item {
      border:1px solid var(--border);
      border-radius:var(--radius);
      margin-bottom:10px;
      overflow:hidden;
    }
    .faq-question {
      width:100%;
      background:var(--bg-card);
      border:none;
      color:var(--text-primary);
      text-align:left;
      padding:18px 20px;
      font-size:.95rem;
      font-weight:600;
      cursor:pointer;
      display:flex;
      justify-content:space-between;
      align-items:center;
      transition:background .2s;
    }
    .faq-question:hover { background:rgba(180,74,255,0.06); }
    .faq-question .faq-icon { transition:transform .3s; font-size:1.2rem; }
    .faq-item.open .faq-icon { transform:rotate(45deg); }
    .faq-answer {
      max-height:0;
      overflow:hidden;
      transition:max-height .3s ease;
    }
    .faq-item.open .faq-answer { max-height:400px; }
    .faq-answer-inner {
      padding:0 20px 18px;
      color:var(--text-secondary);
      font-size:.9rem;
      line-height:1.6;
    }

    /* ========== FOOTER ========== */
    .footer {
      padding:60px 0 30px;
      border-top:1px solid var(--border);
    }
    .footer-grid {
      display:grid;
      grid-template-columns: repeat(auto-fit, minmax(200px,1fr));
      gap:32px;
      margin-bottom:40px;
    }
    .footer h4 { font-size:.95rem; font-weight:700; margin-bottom:12px; }
    .footer p, .footer a { color:var(--text-secondary); font-size:.85rem; }
    .footer ul li { margin-bottom:8px; }
    .footer-bottom {
      text-align:center;
      padding-top:24px;
      border-top:1px solid var(--border);
      color:var(--text-secondary);
      font-size:.8rem;
    }

    /* ========== MODAL ========== */
    .modal-overlay {
      position:fixed; inset:0;
      background:rgba(0,0,0,0.7);
      z-index:200;
      opacity:0; pointer-events:none;
      transition:opacity .3s;
    }
    .modal-overlay.active { opacity:1; pointer-events:all; }
    .preference-modal {
      position:fixed;
      top:50%; left:50%;
      transform:translate(-50%,-50%) scale(0.9);
      background:#1a1a2e;
      border:1px solid var(--border);
      border-radius:var(--radius-lg);
      padding:40px 32px;
      z-index:201;
      text-align:center;
      max-width:420px;
      width:90%;
      opacity:0; pointer-events:none;
      transition:opacity .3s, transform .3s;
    }
    .preference-modal.active { opacity:1; pointer-events:all; transform:translate(-50%,-50%) scale(1); }
    .modal-close {
      position:absolute; top:14px; right:18px;
      background:none; border:none; color:var(--text-secondary);
      font-size:1.8rem; cursor:pointer; line-height:1;
    }
    .modal-close:hover { color:#fff; }
    .modal-title { font-size:1.3rem; font-weight:800; margin-bottom:6px; }
    .modal-subtitle { color:var(--text-secondary); font-size:.9rem; margin-bottom:28px; }
    .pref-options { display:flex; gap:12px; justify-content:center; flex-wrap:wrap; margin-bottom:20px; }
    .pref-btn {
      background:var(--bg-card);
      border:1px solid var(--border);
      border-radius:var(--radius);
      padding:20px 28px;
      cursor:pointer;
      text-align:center;
      color:#fff;
      transition:border-color .2s, transform .2s, background .2s;
    }
    .pref-btn:hover { border-color:var(--accent-purple); transform:translateY(-2px); background:rgba(180,74,255,0.1); }
    .pref-icon { font-size:2rem; margin-bottom:6px; }
    .pref-label { font-size:.88rem; font-weight:600; }
    .modal-note { color:var(--text-secondary); font-size:.78rem; }

    /* ========== RESPONSIVE ========== */
    @media(max-width:480px){
      .hero h1 { font-size:1.7rem; }
      .section-title { font-size:1.4rem; }
      .features-grid { grid-template-columns:1fr; }
      .modes-grid { grid-template-columns:repeat(2,1fr); }
      .pricing-grid { grid-template-columns:1fr; }
    }

(function() {
      var popupOverlay = document.getElementById('popup-overlay');
      var popupModal = document.getElementById('popup-modal');
      var popupClose = document.getElementById('popup-close');

      function openPopup() {
        if (popupOverlay && popupModal) {
          popupOverlay.classList.add('active');
          popupModal.classList.add('active');
        }
      }

      window.closePopup = function() {
        if (popupOverlay && popupModal) {
          popupOverlay.classList.remove('active');
          popupModal.classList.remove('active');
        }
      };

      // Auto-open after 3s, 1x per session
      if (!sessionStorage.getItem('popupShown')) {
        setTimeout(function() {
          openPopup();
          sessionStorage.setItem('popupShown', 'true');
        }, 3000);
      }

      // Close handlers
      if (popupClose) popupClose.addEventListener('click', closePopup);
      if (popupOverlay) popupOverlay.addEventListener('click', closePopup);
      document.addEventListener('keydown', function(e) {
        if (e.key === 'Escape') closePopup();
      });
    })();

document.querySelectorAll('.faq-question').forEach(function(btn) {
      btn.addEventListener('click', function() {
        var item = this.closest('.faq-item');
        var wasOpen = item.classList.contains('open');
        document.querySelectorAll('.faq-item').forEach(function(el){ el.classList.remove('open'); });
        if (!wasOpen) item.classList.add('open');
      });
    });

